/**
 * @fileoverview Button component — modular entry point.
 *
 * @module module/Button
 */

import { default as razyui } from '../../index.js';
import { StateMachine } from '../shared/StateMachine.js';
import { ButtonDef as DEF } from '../Button.def.js';

import { DEFAULTS, CLS } from './constants.js';
import { SM_EFFECTS, setupDOM, cleanupDOM } from './view.js';
import { bindEvents } from './events.js';

/**
 * Button — interactive button component (JIT-compatible)
 *
 * Features:
 *   - Seven variants: primary, success, warning, danger, neutral, ghost, outline
 *   - Three sizes: sm, md (default), lg
 *   - Loading state with spinner
 *   - Disabled state
 *   - Icon slots (left, right)
 *   - Icon-only mode
 *   - Keyboard support (Enter, Space)
 *   - ARIA states (aria-busy, aria-disabled)
 *
 * @param {string|Element} selector
 * @param {object} [config]
 */
const Button = class {
    #root      = null;
    #destroyed = false;
    #labelEl   = null;
    #spinnerEl = null;
    #sm        = null;
    #config    = {};
    #eventAC   = null;

    constructor(selector, config = {}) {
        const root = razyui(selector);

        if (!root.length) {
            console.warn('Button: element not found \u2192', selector);
            return;
        }

        this.#root   = root;
        this.#config = { ...DEFAULTS, ...config };
        this.#init();
    }

    #init() {
        const root   = this.#root;
        const config = this.#config;

        // Set role and tabindex for non-button elements
        const el = root[0];
        if (el.tagName !== 'BUTTON') {
            el.setAttribute('role', 'button');
            el.setAttribute('tabindex', '0');
        }
        if (config.type && el.tagName === 'BUTTON') {
            el.setAttribute('type', config.type);
        }

        // 1. View
        const { labelEl, spinnerEl } = setupDOM(root, config);
        this.#labelEl   = labelEl;
        this.#spinnerEl = spinnerEl;

        // Cache child element refs for state machine effects (avoids querySelector per state change)
        const refs = {
            spinner: spinnerEl?.[0] ?? null,
            label:   labelEl?.[0] ?? null,
            icons:   root[0].querySelectorAll('.' + CLS.ICON),
        };

        // 2. State machine
        const sm = new StateMachine({
            initial: 'idle',
            states: {
                idle:     { on: { LOAD: 'loading', DISABLE: 'disabled' } },
                loading:  { on: { LOADED: 'idle', DISABLE: 'disabled' } },
                disabled: { on: { ENABLE: 'idle' } },
            },
            effects: SM_EFFECTS,
        }, { root, refs });
        this.#sm = sm;

        // 3. Events
        this.#eventAC = bindEvents(root, {
            disabled: () => this.#sm.current === 'disabled',
            loading:  () => this.#sm.current === 'loading',
            onClick:  config.onClick,
        });

        // 4. Apply initial state
        if (config.disabled) sm.send('DISABLE');
        else if (config.loading) sm.send('LOAD');
    }

    // ── Public API ──

    /** Set loading state. */
    setLoading(loading) {
        if (loading && this.#sm.current === 'idle') {
            this.#sm.send('LOAD');
            this.#spinnerEl.show();
        } else if (!loading && this.#sm.current === 'loading') {
            this.#sm.send('LOADED');
            this.#spinnerEl.hide();
        }
    }

    /** Set disabled state. */
    setDisabled(disabled) {
        if (disabled) {
            this.#sm.send('DISABLE');
        } else if (this.#sm.current === 'disabled') {
            this.#sm.send('ENABLE');
        }
    }

    /** Update button text. */
    setText(text) {
        if (this.#labelEl) {
            this.#labelEl[0].textContent = text;
        }
    }

    /** Get current state. */
    get state() {
        return this.#sm.current;
    }

    /** Get control object for external manipulation. */
    getControl() {
        const self = this;
        return {
            get disabled()  { return self.state === 'disabled'; },
            set disabled(v) { self.setDisabled(v); },
            get loading()   { return self.state === 'loading'; },
            set loading(v)  { self.setLoading(v); },
            setLoading:  (v) => self.setLoading(v),
            setDisabled: (v) => self.setDisabled(v),
            setText:     (v) => self.setText(v),
            get state()  { return self.state; },
            destroy:     () => self.destroy(),
            get element() { return self.#root[0]; },
            get destroyed() { return self.#destroyed; },
        };
    }

    /** Destroy the component. */
    destroy() {
        if (this.#destroyed) return;
        this.#destroyed = true;
        this.#eventAC?.abort();
        cleanupDOM(this.#root);
    }
};

export default Button;
